#include<bits/stdc++.h>
using namespace std;
long long f[2005],sum[2005],a[2005];
int main() {
	long long n,k,m1=0;
	cin>>n>>k;
	for (int i=1; i<=n; i++) {
		cin>>a[i];
		f[a[i]]+=a[i];
	}
	for (int i=1; i<=1000; i++) {
		sum[i]=sum[i-1]+f[i];
	}
	for (int i=1; i<=1000; i++) {
		m1=max(m1,sum[i+k]-sum[i-1]);
	}
	cout<<m1;
	return 0;
}
